import{C as n,o,c as i,a5 as s,E as l}from"./chunks/framework.CW28V7p_.js";const h=JSON.parse('{"title":"1. Account basics (anatomy)","description":"","frontmatter":{},"headers":[],"relativePath":"module-2/1-account-basics.md","filePath":"module-2/1-account-basics.md","lastUpdated":1780937944000}'),r={name:"module-2/1-account-basics.md"},u=Object.assign(r,{setup(c){const e={id:"m2-1-account-basics",title:"🧠 Mini-check: Account basics",intro:"3 питання — account anatomy.",questions:[{type:"mcq",q:"Що з цього є полями account на Solana? (обери всі правильні)",options:["lamports (balance у lamports = 0.000000001 SOL)","owner (program який володіє account)","data (byte array з custom state)","username і email власника"],correct:[0,1,2],explanation:"Account має: lamports (balance), owner (program), data (bytes), executable (flag), rent_epoch (legacy). НЕМАЄ usernames/emails — Solana покажчики це pubkeys, не людино-читабельні. Module 2.1."},{type:"command",q:"Як подивитись повну інформацію про account за pubkey (наприклад твоєї identity)? Напиши команду.",accepts:["solana account DSDefivSLLox2Sg4buLCfzxdD281H4AaQg3h1vLeBqjt","solana account DSDefivSLLox2Sg4buLCfzxdD281H4AaQg3h1vLeBqjt --url http://localhost:8899","sudo /home/solana/ag/bin/solana account DSDefivSLLox2Sg4buLCfzxdD281H4AaQg3h1vLeBqjt --url http://localhost:8899"],ideal:"solana account DSDefivSLLox2Sg4buLCfzxdD281H4AaQg3h1vLeBqjt",explanation:'solana account <PUBKEY> виводить: balance, owner program, executable flag, data length, rent epoch. Якщо account не існує — "AccountNotFound". Module 2.1.'},{type:"explain",q:'Поясни своїми словами що означає поле "owner" у account і чому це важливо.',ideal:`Owner — це pubkey program який ВОЛОДІЄ accountом. Це НЕ власник у людському сенсі (як wallet owner), а program який має право модифікувати accountа data і lamports.

Приклади:
1. Твій SOL wallet — owner це System Program (11111...). System Program може transfer lamports, але не може писати у data (data порожній).
2. Token account — owner це Token Program (Tokenkeg...). Token Program може mint/burn/transfer tokens у цьому account.
3. Vote account — owner це Vote Program (Vote111...). Тільки Vote Program може записувати votes.

Чому важливо: тільки owner program може модифікувати account state. Хочеш transfer токенів? Виклич Token Program (як owner) — він зробить write. Random program не може торкнутись чужого account.

Це fundamental security model Solana — кожен account "захищений" своїм owner program.`,explanation:"Ключове: owner = program з write access, не людський власник. Security primitive. Module 2.1."}]};return(p,a)=>{const t=n("Quiz");return o(),i("div",null,[a[0]||(a[0]=s("",81)),l(t,{data:e}),a[1]||(a[1]=s("",6))])}}});export{h as __pageData,u as default};
